changeSet.sql:
ALTER TABLE sync_job ADD CONSTRAINT ck_sync_job_type
    CHECK (type IN ('INITIAL','RECONCILIATION','BACKFILL'));
ALTER TABLE sync_job ADD CONSTRAINT ck_sync_job_trigger_source
    CHECK (trigger_source IN ('SCHEDULED','MANUAL','LIFECYCLE','SYSTEM'));
ALTER TABLE sync_job ADD CONSTRAINT ck_sync_job_status
    CHECK (status IN ('PENDING','RUNNING','SUCCEEDED','SUCCEEDED_WITH_WARNINGS','FAILED','CANCELLED'));

UPDATE repository_to_monitor
   SET issue_sync_cursor = NULL
 WHERE issue_sync_cursor IS NOT NULL
   AND NOT (
         issue_backfill_high_water_mark IS NOT NULL
         AND (
           issue_backfill_high_water_mark = 0
           OR COALESCE(issue_backfill_checkpoint, 1) <= 0
         )
       );

UPDATE repository_to_monitor
   SET pull_request_sync_cursor = NULL
 WHERE pull_request_sync_cursor IS NOT NULL
   AND NOT (
         pull_request_backfill_high_water_mark IS NOT NULL
         AND (
           pull_request_backfill_high_water_mark = 0
           OR COALESCE(pull_request_backfill_checkpoint, 1) <= 0
         )
       );
